from src.models.knn_recommender import KNNRecommenderfrom src.preprocessing.data_loader import load_movielens_100kfrom src.preprocessing.matrix_builder import create_user_item_matrixfrom src.utils.translator import Translatorfrom src.models.svd_recommender import SVDModelfrom sklearn.model_selection import train_test_splitdef main():    tr = Translator(lang='pt')    df_ratings, df_items = load_movielens_100k()    train_df, test_df = train_test_split(df_ratings, test_size=0.2, random_state=42)    print("\n" + "="*30)    print("Comparing models")    print("="*30)    sparse_user, matrix_user, means_user = create_user_item_matrix(train_df, is_item_based=False)    knn_user = KNNRecommender(n_neighbors=20)    knn_user.fit(sparse_user)    svd_rec = SVDModel()    svd_rec.train(train_df)    svd_rmse = svd_rec.test_rmse(test_df)    print(f"SVD RMSE: {svd_rmse:.4f}")    pred_rating = svd_rec.predict_rating(1, 1)    print(f"\nSVD prediction (User 1, Toy Story): {pred_rating:.2f}")if __name__ == "__main__":    main()